  ('optician-moex-00680', 'optician', 'optician-moex-111-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '關於隱形眼鏡的特性，下列敘述何者錯誤？', '["計算時通常可以將隱形眼鏡視為一種透鏡", "對近視眼而言，同一隻眼睛配戴隱形眼鏡所需度數會比眼鏡鏡片高", "配戴隱形眼鏡比配戴玻璃鏡片有較大的視場（fieldofview）", "高度近視患者也適合配戴硬式隱形眼鏡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2e66caa9553a", "answer_pdf_sha1": "65ca4667bb73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
